public sealed class TransformationStrategyRegistry
{
    private readonly ILogger _logger;
    private readonly ConcurrentDictionary<string, ITransformationStrategy> _strategies = new();

    public TransformationStrategyRegistry(ILogger<TransformationStrategyRegistry> logger)
    {
        _logger = logger;
        Reload();  // Heavy reflection-based assembly scanning on every instantiation
    }

    /// <summary>
    /// Reloads strategy catalogue by scanning all currently loaded assemblies
    /// for types implementing <see cref="ITransformationStrategy"/>.
    /// </summary>
    public void Reload()
    {
        _strategies.Clear();

        var strategies = AppDomain.CurrentDomain.GetAssemblies()  // Full assembly scan
            .SelectMany(a =>
            {
                try { return a.GetTypes(); }
                catch (ReflectionTypeLoadException rtl) { return rtl.Types.Where(t => t != null)!; }
            })
            .Where(t => !t.IsAbstract && !t.IsInterface && typeof(ITransformationStrategy).IsAssignableFrom(t))
            .Select(Activator.CreateInstance)
            .Cast<ITransformationStrategy>();
        // ... registration logic
    }
```

### Evidence 3: Dataflow Pipeline with Heavy Initialization
```csharp
// File: /app/project/src/module_65.txt
// Lines: 328-413
public sealed class EventTransformationPipeline : IAsyncDisposable
{
    private readonly BufferBlock<WorkActivityEvent>                _input;
    private readonly TransformManyBlock<WorkActivityEvent, MetricDataPoint> _compute;
    private readonly ActionBlock<MetricDataPoint>                  _sink;
    private readonly ILogger                                       _log = Log.ForContext<EventTransformationPipeline>();
    private readonly CancellationTokenSource                        _cts = new();

    public EventTransformationPipeline(
        StrategyRegistry strategyRegistry,
        IMetricSink      metricSink,
        int              maxDegreeOfParallelism = 4,
        int              boundedCapacity        = 1_024)  // Buffer allocation
    {
        // Configure blocks - each requires memory allocation and setup
        _input = new BufferBlock<WorkActivityEvent>(
            new DataflowBlockOptions { BoundedCapacity = boundedCapacity });

        _compute = new TransformManyBlock<WorkActivityEvent, MetricDataPoint>(...);
        _sink = new ActionBlock<MetricDataPoint>(...);

        // Wire-up blocks
        _input.LinkTo(_compute, new DataflowLinkOptions { PropagateCompletion = true });
        _compute.LinkTo(_sink, new DataflowLinkOptions { PropagateCompletion = true });
    }
```

