    42→    {
    43→        public required string EventId          { get; init; }
    44→        public required string EventType        { get; init; }
    45→        public required DateTimeOffset Created  { get; init; }
    46→        public required IReadOnlyDictionary<string, string?> Metadata { get; init; }
