   208→    /// <summary>
   209→    /// Calculates the ratio between focus time and total working hours on a per-user, per-day basis.
   210→    /// Source events:
   211→    ///   - CalendarEventCreated / Updated
   212→    ///   - WorkSessionStarted / Ended (emitted by IDE plugins, CLI wrappers, browser extensions, …)
   213→    /// </summary>
   214→    internal sealed class FocusTimeRatioStrategy : IKpiCalculationStrategy
   215→    {
   216→        private const string CalendarEventType = "CalendarEvent";
   217→        private const string WorkSessionType   = "WorkSession";
   218→
   219→        public string KpiName => "focus_time_ratio";
   220→
   221→        public bool CanHandle(EventEnvelope envelope)
   222→            => envelope.EventType is CalendarEventType or WorkSessionType;
   223→
   224→        public async ValueTask<IEnumerable<KpiCalculationResult>> ProcessAsync(
   225→            EventEnvelope   envelope,
   226→            CancellationToken ct = default)
   227→        {
   228→            // NOTE: In a real-world scenario, we would use a distributed cache (e.g., DAX or Redis)
   229→            //       to store partial aggregates.  For brevity, this implementation simply returns
   230→            //       an immediate KPI row when sufficient information is present on the event itself.
   231→
   232→            if (envelope.EventType == WorkSessionType &&
   233→                envelope.Metadata.TryGetValue("DurationMinutes", out var durationStr) &&
   234→                int.TryParse(durationStr, out var durationMinutes))
   235→            {
   236→                var userId = envelope.Metadata["UserId"]!;
   237→                var date   = envelope.Created.UtcDateTime.Date;
   238→
   239→                var result = new KpiCalculationResult
   240→                {
   241→                    KpiName        = KpiName,
   242→                    WindowStartUtc = date,
   243→                    WindowEndUtc   = date.AddDays(1),
   244→                    Value          = durationMinutes, // later aggregated to obtain total focus time
   245→                    Dimensions = new Dictionary<string, string>
   246→                    {
   247→                        ["user_id"] = userId,
   248→                        ["metric"]  = "focus_minutes"
   249→                    }
   250→                };
   251→
   252→                return new[] { result };
   253→            }
   254→
   255→            if (envelope.EventType == CalendarEventType &&
   256→                envelope.Metadata.TryGetValue("DurationMinutes", out var calendarDurationStr) &&
   257→                int.TryParse(calendarDurationStr, out var meetingMinutes))
   258→            {
   259→                var userId = envelope.Metadata["OrganizerId"]!;
   260→                var date   = envelope.Created.UtcDateTime.Date;
   261→
   262→                var result = new KpiCalculationResult
   263→                {
   264→                    KpiName        = KpiName,
   265→                    WindowStartUtc = date,
   266→                    WindowEndUtc   = date.AddDays(1),
   267→                    Value          = meetingMinutes,
   268→                    Dimensions = new Dictionary<string, string>
   269→                    {
   270→                        ["user_id"] = userId,
   271→                        ["metric"]  = "meeting_minutes"
   272→                    }
   273→                };
   274→
   275→                return new[] { result };
   276→            }
   277→
   278→            return Array.Empty<KpiCalculationResult>();
   279→        }
   280→    }
