   372→    /// <summary>
   373→    /// Simple abstraction that serialises KPI rows as ND-JSON and stores them in S3.
   374→    /// Real-world implementation could write Apache Parquet or Iceberg; ND-JSON keeps demo lightweight.
   375→    /// </summary>
   376→    public interface IS3KpiWriter : IAsyncDisposable
