   383→    /// <summary>
   384→    /// Production-ready S3 writer implementation with retry/back-off and partitioned key structure.
   385→    /// </summary>
   386→    internal sealed class S3KpiWriter : IS3KpiWriter
   387→    {
   388→        private readonly IAmazonS3                 _s3;
   389→        private readonly string                    _bucket;
   390→        private readonly ILogger<S3KpiWriter>      _logger;
   391→
   392→        private static readonly AmazonS3RetryPolicy RetryPolicy = new();
   393→
   394→        public S3KpiWriter(IAmazonS3 s3, string bucket, ILogger<S3KpiWriter> logger)
   395→        {
   396→            _s3     = s3     ?? throw new ArgumentNullException(nameof(s3));
   397→            _bucket = bucket ?? throw new ArgumentNullException(nameof(bucket));
   398→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   399→        }
   400→
   401→        public async ValueTask WriteAsync(
   402→            IEnumerable<KpiCalculationResult> rows,
   403→            CancellationToken                 ct = default)
   404→        {
   405→            ArgumentNullException.ThrowIfNull(rows);
   406→
   407→            var nowUtc     = DateTime.UtcNow;
   408→            var partition  = $"{nowUtc:yyyy/MM/dd}";
   409→            var objectKey  = $"kpi/partition_date={partition}/{Guid.NewGuid():N}.jsonl";
   410→
   411→            // Serialise as ND-JSON
   412→            var jsonLines  = string.Join('\n', rows.Select(row => System.Text.Json.JsonSerializer.Serialize(row)));
