   351→    /// back to logging.
   352→    /// </summary>
   353→    public sealed class FireAndForgetDispatcher : ITransformedEventDispatcher, IDisposable
   354→    {
   355→        private readonly ILogger _log;
   356→        private readonly IAmazonKinesis _kinesis;
   357→        private readonly string _targetStreamName;
   358→        private readonly ConcurrentQueue<Amazon.Kinesis.Model.PutRecordsRequestEntry> _buffer = new();
   359→
   360→        public FireAndForgetDispatcher(ILogger log)
   361→        {
   362→            _log              = log;
   363→            _kinesis          = new AmazonKinesisClient(); // region inferred from Lambda environment
   364→            _targetStreamName = Environment.GetEnvironmentVariable("TRANSFORMED_STREAM_NAME") 
   365→                                ?? "pulseops-transformed-events";
