   368→        public Task DispatchAsync(TransformedEvent evt, CancellationToken ct)
   369→        {
   370→            var json   = JsonSerializer.Serialize(evt);
   371→            var record = new Amazon.Kinesis.Model.PutRecordsRequestEntry
   372→            {
   373→                PartitionKey = evt.Tags.TryGetValue("source", out var source) ? source : "unknown",
   374→                Data         = new MemoryStream(Encoding.UTF8.GetBytes(json))
   375→            };
   376→
   377→            _buffer.Enqueue(record);
   378→
   379→            // Flush in background if we crossed threshold (imperfect, but keeps demo short)
   380→            if (_buffer.Count >= 500)
   381→            {
   382→                _ = FlushAsync(CancellationToken.None);
   383→            }
   384→
   385→            return Task.CompletedTask;
   386→        }
