   124→    /// <summary>
   125→    /// Strategy that emits raw focus-time minutes for Focus activities.
   126→    /// Additional ratio aggregation is done downstream in Athena/QuickSight.
   127→    /// </summary>
   128→    public sealed class FocusTimeStrategy : IMetricComputationStrategy
   129→    {
   130→        private static readonly MetricDataPoint[] Empty = Array.Empty<MetricDataPoint>();
   131→
   132→        public bool CanHandle(in WorkActivityEvent workEvent)
   133→            => workEvent.Activity == ActivityType.Focus;
   134→
   135→        public ValueTask<IReadOnlyCollection<MetricDataPoint>> ComputeAsync(
   136→            WorkActivityEvent workEvent,
   137→            CancellationToken cancellationToken = default)
   138→        {
   139→            double minutes = workEvent.Duration.TotalMinutes;
   140→
   141→            if (minutes <= 0)
   142→            {
   143→                return ValueTask.FromResult<IReadOnlyCollection<MetricDataPoint>>(Empty);
   144→            }
   145→
   146→            var dp = new MetricDataPoint(
   147→                workEvent.UserId,
   148→                MetricName: "focus_time_minutes",
   149→                Value: Math.Round(minutes, 2, MidpointRounding.AwayFromZero),
   150→                Timestamp: workEvent.EndUtc,
   151→                Dimensions: new Dictionary<string, string>(StringComparer.Ordinal)
   152→                {
   153→                    ["activity_type"] = workEvent.Activity.ToString()
   154→                });
   155→
   156→            return ValueTask.FromResult<IReadOnlyCollection<MetricDataPoint>>(
   157→                new[] { dp });
   158→        }
   159→    }
