   161→    /// <summary>
   162→    /// Strategy that calculates the total cost of a meeting based on its
   163→    /// duration and participants’ assumed hourly rate injected through metadata.
   164→    /// </summary>
   165→    public sealed class MeetingCostIndexStrategy : IMetricComputationStrategy
   166→    {
   167→        private static readonly MetricDataPoint[] Empty = Array.Empty<MetricDataPoint>();
   168→
   169→        private readonly double _defaultHourlyRateUsd;
   170→
   171→        public MeetingCostIndexStrategy(double defaultHourlyRateUsd = 75)
   172→        {
   173→            if (defaultHourlyRateUsd <= 0)
   174→                throw new ArgumentOutOfRangeException(
   175→                    nameof(defaultHourlyRateUsd),
   176→                    "Hourly rate must be positive.");
   177→
   178→            _defaultHourlyRateUsd = defaultHourlyRateUsd;
   179→        }
   180→
   181→        public bool CanHandle(in WorkActivityEvent workEvent)
   182→            => workEvent.Activity == ActivityType.Meeting;
   183→
   184→        public async ValueTask<IReadOnlyCollection<MetricDataPoint>> ComputeAsync(
   185→            WorkActivityEvent workEvent,
   186→            CancellationToken cancellationToken = default)
   187→        {
   188→            // Guard against malformed events early; no metrics emitted.
   189→            if (workEvent.Duration <= TimeSpan.Zero)
   190→                return Empty;
   191→
   192→            // Extract meeting metadata (participants, rate override, etc.)
   193→            int participantCount = 0;
   194→            double? hourlyRateOverride = null;
   195→
   196→            if (!string.IsNullOrWhiteSpace(workEvent.Metadata))
   197→            {
   198→                try
   199→                {
   200→                    var meetingMeta = JsonSerializer.Deserialize<MeetingMetadata>(
   201→                        workEvent.Metadata,
   202→                        SerializerOptions.Default);
   203→
   204→                    if (meetingMeta is not null)
   205→                    {
   206→                        participantCount   = meetingMeta.ParticipantCount ?? participantCount;
   207→                        hourlyRateOverride = meetingMeta.HourlyRateUsd;
   208→                    }
   209→                }
   210→                catch (JsonException ex)
   211→                {
   212→                    Log.Warning(
   213→                        ex,
   214→                        "Failed to deserialize meeting metadata for event {EventId}. Raw: {Raw}",
   215→                        workEvent.GetHashCode(),
   216→                        workEvent.Metadata);
   217→                }
   218→            }
   219→
   220→            participantCount = Math.Max(participantCount, 1); // At least one person.
   221→            double hourlyRate = hourlyRateOverride ?? _defaultHourlyRateUsd;
   222→
   223→            double costUsd = participantCount *
   224→                             hourlyRate *
   225→                             workEvent.Duration.TotalHours;
   226→
   227→            var dp = new MetricDataPoint(
   228→                workEvent.UserId,
   229→                MetricName: "meeting_cost_usd",
   230→                Value: Math.Round(costUsd, 2, MidpointRounding.AwayFromZero),
   231→                Timestamp: workEvent.EndUtc,
   232→                Dimensions: new Dictionary<string, string>(StringComparer.Ordinal)
   233→                {
   234→                    ["participant_count"] = participantCount.ToString(CultureInfo.InvariantCulture),
   235→                    ["hourly_rate"]       = hourlyRate.ToString("F2", CultureInfo.InvariantCulture)
   236→                });
   237→
   238→            return new[] { dp };
   239→        }
   240→
   241→        // Internal DTO to map metadata JSON.
   242→        private sealed record MeetingMetadata
   243→        {
   244→            [JsonPropertyName("participantCount")]
   245→            public int?   ParticipantCount { get; init; }
   246→
   247→            [JsonPropertyName("hourlyRateUsd")]
   248→            public double? HourlyRateUsd   { get; init; }
   249→        }
