   328→    public sealed class EventTransformationPipeline : IAsyncDisposable
   329→    {
   330→        private readonly BufferBlock<WorkActivityEvent>                _input;
   331→        private readonly TransformManyBlock<WorkActivityEvent, MetricDataPoint> _compute;
   332→        private readonly ActionBlock<MetricDataPoint>                  _sink;
   333→        private readonly ILogger                                       _log = Log.ForContext<EventTransformationPipeline>();
   334→        private readonly CancellationTokenSource                        _cts = new();
   335→
   336→        public EventTransformationPipeline(
   337→            StrategyRegistry strategyRegistry,
   338→            IMetricSink      metricSink,
   339→            int              maxDegreeOfParallelism = 4,
   340→            int              boundedCapacity        = 1_024)
   341→        {
   342→            ArgumentNullException.ThrowIfNull(strategyRegistry);
   343→            ArgumentNullException.ThrowIfNull(metricSink);
   344→
   345→            // Configure blocks
   346→            _input = new BufferBlock<WorkActivityEvent>(
   347→                new DataflowBlockOptions
   348→                {
   349→                    BoundedCapacity = boundedCapacity
   350→                });
   351→
   352→            _compute = new TransformManyBlock<WorkActivityEvent, MetricDataPoint>(
   353→                async (workEvent) =>
   354→                {
   355→                    try
   356→                    {
   357→                        if (strategyRegistry.TryResolve(workEvent, out var strategy))
   358→                        {
   359→                            return await strategy.ComputeAsync(
   360→                                workEvent,
   361→                                _cts.Token);
   362→                        }
   363→
   364→                        _log.Debug("No strategy matched event {@Event}", workEvent);
   365→                        return Array.Empty<MetricDataPoint>();
   366→                    }
   367→                    catch (Exception ex)
   368→                    {
   369→                        _log.Error(
   370→                            ex,
   371→                            "Metric computation failed for event {@Event}",
   372→                            workEvent);
   373→                        return Array.Empty<MetricDataPoint>();
   374→                    }
   375→                },
   376→                new ExecutionDataflowBlockOptions
   377→                {
   378→                    MaxDegreeOfParallelism = maxDegreeOfParallelism,
   379→                    BoundedCapacity        = boundedCapacity,
   380→                    CancellationToken      = _cts.Token,
   381→                    EnsureOrdered          = false
   382→                });
   383→
   384→            _sink = new ActionBlock<MetricDataPoint>(
   385→                async (metric) =>
   386→                {
   387→                    try
   388→                    {
   389→                        await metricSink.WriteAsync(
   390→                            new[] { metric },
   391→                            _cts.Token);
   392→                    }
   393→                    catch (Exception ex)
   394→                    {
   395→                        _log.Error(
   396→                            ex,
   397→                            "Failed to write metric {@Metric}",
   398→                            metric);
   399→                        // In production, failed metrics would be forwarded to a DLQ.
   400→                    }
   401→                },
   402→                new ExecutionDataflowBlockOptions
   403→                {
   404→                    MaxDegreeOfParallelism = maxDegreeOfParallelism,
   405→                    BoundedCapacity        = boundedCapacity,
   406→                    CancellationToken      = _cts.Token,
   407→                    EnsureOrdered          = false
   408→                });
   409→
   410→            // Wire-up blocks
   411→            _input.LinkTo(_compute,                    new DataflowLinkOptions { PropagateCompletion = true });
   412→            _compute.LinkTo(_sink,                     new DataflowLinkOptions { PropagateCompletion = true });
   413→        }
   414→
   415→        /// <summary>
   416→        /// Enqueues a new event for processing.  Respects back-pressure.
   417→        /// </summary>
   418→        public async Task SubmitAsync(
   419→            WorkActivityEvent  workEvent,
   420→            CancellationToken  cancellationToken = default)
   421→        {
   422→            if (!_input.Post(workEvent))
   423→            {
   424→                await _input.SendAsync(workEvent, cancellationToken);
   425→            }
   426→        }
   427→
   428→        /// <summary>
   429→        /// Signals graceful shutdown and waits until all buffered work completes.
   430→        /// </summary>
   431→        public async Task CompleteAsync(CancellationToken cancellationToken = default)
   432→        {
   433→            _input.Complete();
   434→            try
   435→            {
   436→                await _sink.Completion.WaitAsync(cancellationToken);
   437→            }
   438→            catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
   439→            {
   440→                _cts.Cancel();
   441→                throw;
   442→            }
   443→        }
   444→
   445→        public async ValueTask DisposeAsync()
   446→        {
   447→            _cts.Cancel();
   448→            _input.Complete();
   449→
   450→            try
   451→            {
   452→                await _sink.Completion;
   453→            }
   454→            catch
   455→            {
   456→                // Swallow any in-flight exceptions on dispose.
   457→            }
   458→
   459→            _cts.Dispose();
   460→        }
   461→    }
