   267→        /// </summary>
   268→        private static IDictionary<string, ITransformationStrategy> DiscoverStrategies(IEnumerable<Assembly> assemblies)
   269→        {
   270→            var dict = new ConcurrentDictionary<string, ITransformationStrategy>(StringComparer.OrdinalIgnoreCase);
   271→
   272→            foreach (var assembly in assemblies)
   273→            {
   274→                var strategyTypes = assembly
   275→                    .GetTypes()
   276→                    .Where(t => !t.IsAbstract && typeof(ITransformationStrategy).IsAssignableFrom(t));
   277→
   278→                foreach (var type in strategyTypes)
