    46→        private static readonly Lazy<ServiceProvider> _serviceProvider = new(
    47→            BuildServiceProvider, LazyThreadSafetyMode.ExecutionAndPublication);
    48→
    49→        private static ServiceProvider BuildServiceProvider()
    50→        {
    51→            var services = new ServiceCollection();
    52→
    53→            // Logging
    54→            services.AddLogging(cfg => cfg.AddLambdaLogger());
    55→
    56→            // AWS clients
    57→            services.AddDefaultAWSOptions(new Amazon.Extensions.NETCore.Setup.AWSOptions
    58→            {
    59→                Region = RegionEndpoint.USEast1
    60→            });
    61→            services.AddAWSService<IAmazonS3>();
    62→
    63→            // Strategy registry & concrete strategies
    64→            services.AddSingleton<IMetricStrategyRegistry, MetricStrategyRegistry>();
    65→
    66→            // Register built-in strategies
    67→            services.AddSingleton<IMetricTransformationStrategy, FocusTimeRatioStrategy>();
    68→            services.AddSingleton<IMetricTransformationStrategy, MeetingCostIndexStrategy>();
    69→            services.AddSingleton<IMetricTransformationStrategy, DeploymentLeadTimeStrategy>();
    70→
    71→            // Metrics publisher
    72→            services.AddSingleton<IMetricPublisher, S3MetricPublisher>();
    73→
    74→            return services.BuildServiceProvider();
    75→        }
    76→
    77→        /// <summary>
    78→        /// Main Lambda handler.
    79→        /// </summary>
    80→        /// <param name="kinesisEvent">Batch of Kinesis records.</param>
    81→        /// <param name="context">Execution context.</param>
    82→        public async Task HandlerAsync(KinesisEvent kinesisEvent, ILambdaContext context)
    83→        {
    84→            var sp          = _serviceProvider.Value;
    85→            var logger      = sp.GetRequiredService<ILogger<CalendarMetricLambda>>();
    86→            var registry    = sp.GetRequiredService<IMetricStrategyRegistry>();
    87→            var publisher   = sp.GetRequiredService<IMetricPublisher>();
    88→
    89→            using var cts = new CancellationTokenSource(context.RemainingTime - TimeSpan.FromSeconds(2));
    90→
    91→            var publishTasks = new List<Task>();
    92→
    93→            foreach (var record in kinesisEvent.Records)
    94→            {
    95→                try
    96→                {
    97→                    var envelope = DeserializeEnvelope(record);
    98→                    var strategy = registry.Resolve(envelope.MetricType);
    99→
   100→                    if (strategy is null)
   101→                    {
   102→                        logger.LogWarning("No strategy registered for metricType '{MetricType}'.  RecordId={RecordId}", envelope.MetricType, record.EventID);
   103→                        continue;
   104→                    }
   105→
   106→                    var metric = await strategy.TransformAsync(envelope, cts.Token);
   107→                    publishTasks.Add(publisher.PublishAsync(metric, cts.Token));
   108→                }
   109→                catch (OperationCanceledException) when (cts.IsCancellationRequested)
   110→                {
   111→                    logger.LogWarning("Execution cancelled due to nearing timeout.");
   112→                    break;
   113→                }
   114→                catch (Exception ex)
   115→                {
   116→                    logger.LogError(ex, "Failed to process recordId={RecordId}", record.EventID);
   117→                    // NOTE: Rethrow to move the batch to DLQ (configured in Lambda event source mapping)
   118→                    throw;
   119→                }
   120→            }
   121→
   122→            await Task.WhenAll(publishTasks);
   123→        }
