   125→        private static EventEnvelope DeserializeEnvelope(KinesisEvent.KinesisEventRecord record)
   126→        {
   127→            // Kinesis.data is Base64-encoded by contract.
   128→            var jsonBytes = record.Kinesis.Data.ToArray();
   129→            return JsonSerializer.Deserialize<EventEnvelope>(jsonBytes) 
   130→                   ?? throw new InvalidDataException($"Record {record.EventID} produced null deserialization.");
   131→        }
   132→    }
