   134→    #endregion
   135→
   136→    #region Domain Model
   137→
   138→    /// <summary>
   139→    /// The raw, unprocessed envelope coming in from the ingestion pipeline.
   140→    /// </summary>
   141→    public sealed record EventEnvelope
   142→    {
   143→        [JsonPropertyName("metricType")]  public string MetricType  { get; init; } = default!;
   144→        [JsonPropertyName("timestamp")]   public DateTime Timestamp { get; init; }
   145→        [JsonPropertyName("payload")]     public JsonElement Payload { get; init; }
   146→        [JsonPropertyName("tenantId")]    public string TenantId    { get; init; } = default!;
   147→        [JsonPropertyName("source")]      public string Source      { get; init; } = default!;
   148→        [JsonPropertyName("metadata")]    public JsonElement Metadata { get; init; }
   149→    }
   150→
   151→    /// <summary>
   152→    /// Normalized KPI ready for downstream storage (Parquet, S3, Athena, etc.)
   153→    /// </summary>
   154→    public sealed record MetricRecord
   155→    {
   156→        public string        MetricType { get; init; } = default!;
   157→        public string        TenantId   { get; init; } = default!;
   158→        public DateTime      PeriodEnd  { get; init; }
   159→        public double        Value      { get; init; }
   160→        public IReadOnlyDictionary<string, string> Dimensions { get; init; } = default!;
   161→        public JsonDocument  RawPayload { get; init; } = default!;
   162→    }
   163→
   164→    #endregion
   165→
   166→    #region Strategy Infrastructure
   167→
   168→    public interface IMetricTransformationStrategy
   169→    {
   170→        /// <summary>Unique identifier matching EventEnvelope.metricType.</summary>
   171→        string MetricType { get; }
   172→
   173→        /// <summary>
   174→        /// Transforms a domain-specific event envelope into a KPI record.
   175→        /// </summary>
   176→        Task<MetricRecord> TransformAsync(EventEnvelope envelope, CancellationToken token);
   177→    }
   178→
   179→    public interface IMetricStrategyRegistry
   180→    {
   181→        IMetricTransformationStrategy? Resolve(string metricType);
   182→    }
   183→
   184→    public sealed class MetricStrategyRegistry : IMetricStrategyRegistry
   185→    {
   186→        private readonly ConcurrentDictionary<string, IMetricTransformationStrategy> _strategies;
   187→
   188→        public MetricStrategyRegistry(IEnumerable<IMetricTransformationStrategy> strategies)
   189→        {
   190→            _strategies = new ConcurrentDictionary<string, IMetricTransformationStrategy>(StringComparer.OrdinalIgnoreCase);
   191→            foreach (var s in strategies)
   192→            {
   193→                if (!_strategies.TryAdd(s.MetricType, s))
   194→                {
   195→                    throw new InvalidOperationException($"Duplicate strategy for metricType '{s.MetricType}'.");
   196→                }
   197→            }
   198→        }
   199→
   200→        public IMetricTransformationStrategy? Resolve(string metricType)
   201→            => _strategies.TryGetValue(metricType, out var strategy) ? strategy : null;
   202→    }
   203→
   204→    #endregion
   205→
   206→    #region Concrete Strategies
   207→
   208→    internal sealed class FocusTimeRatioStrategy : IMetricTransformationStrategy
   209→    {
   210→        public string MetricType => "focus_time_ratio";
   211→
   212→        public Task<MetricRecord> TransformAsync(EventEnvelope envelope, CancellationToken token)
   213→        {
   214→            // Example logic: count "deep-work" events vs total events in time window.
   215→            var totalMeetings   = envelope.Payload.GetProperty("totalSlots").GetInt32();
   216→            var deepWorkSlots   = envelope.Payload.GetProperty("deepWorkSlots").GetInt32();
   217→            var ratio           = totalMeetings == 0 ? 1 : (double)deepWorkSlots / totalMeetings;
   218→
   219→            var record = new MetricRecord
   220→            {
   221→                MetricType  = MetricType,
   222→                TenantId    = envelope.TenantId,
   223→                PeriodEnd   = envelope.Timestamp,
   224→                Value       = Math.Round(ratio, 4),
   225→                Dimensions  = new Dictionary<string, string>
   226→                {
   227→                    ["source"] = envelope.Source
   228→                },
   229→                RawPayload  = JsonDocument.Parse(envelope.Payload.GetRawText())
   230→            };
   231→
   232→            return Task.FromResult(record);
   233→        }
   234→    }
   235→
   236→    internal sealed class MeetingCostIndexStrategy : IMetricTransformationStrategy
   237→    {
   238→        public string MetricType => "meeting_cost_index";
   239→
   240→        public Task<MetricRecord> TransformAsync(EventEnvelope envelope, CancellationToken token)
   241→        {
   242→            // Example logic: sum attendee hourly rates × meeting duration.
   243→            var durationMins = envelope.Payload.GetProperty("durationMinutes").GetDouble();
   244→            var hourlyRate   = envelope.Payload.GetProperty("avgHourlyRate").GetDouble();
   245→            var attendeeCnt  = envelope.Payload.GetProperty("attendeeCount").GetInt32();
   246→
   247→            var cost = (durationMins / 60.0) * hourlyRate * attendeeCnt;
   248→
   249→            var record = new MetricRecord
   250→            {
   251→                MetricType = MetricType,
   252→                TenantId   = envelope.TenantId,
   253→                PeriodEnd  = envelope.Timestamp,
   254→                Value      = Math.Round(cost, 2),
   255→                Dimensions = new Dictionary<string, string>
   256→                {
   257→                    ["currency"] = "USD"
   258→                },
   259→                RawPayload = JsonDocument.Parse(envelope.Payload.GetRawText())
   260→            };
   261→
   262→            return Task.FromResult(record);
   263→        }
   264→    }
   265→
   266→    internal sealed class DeploymentLeadTimeStrategy : IMetricTransformationStrategy
   267→    {
   268→        public string MetricType => "deployment_lead_time";
   269→
   270→        public Task<MetricRecord> TransformAsync(EventEnvelope envelope, CancellationToken token)
   271→        {
   272→            var commitTs  = envelope.Payload.GetProperty("commitTimestamp").GetDateTime();
   273→            var deployTs  = envelope.Payload.GetProperty("deployTimestamp").GetDateTime();
   274→
   275→            var leadTimeHrs = (deployTs - commitTs).TotalHours;
   276→
   277→            var record = new MetricRecord
   278→            {
   279→                MetricType = MetricType,
   280→                TenantId   = envelope.TenantId,
   281→                PeriodEnd  = deployTs,
   282→                Value      = Math.Round(leadTimeHrs, 2),
   283→                Dimensions = new Dictionary<string, string>
   284→                {
   285→                    ["repository"] = envelope.Payload.GetProperty("repository").GetString() ?? "unknown"
   286→                },
   287→                RawPayload = JsonDocument.Parse(envelope.Payload.GetRawText())
   288→            };
   289→
   290→            return Task.FromResult(record);
   291→        }
   292→    }
   293→
   294→    #endregion
