   297→
   298→    public interface IMetricPublisher
   299→    {
   300→        Task PublishAsync(MetricRecord record, CancellationToken token);
   301→    }
   302→
   303→    /// <summary>
   304→    /// Persists metrics to S3 as newline-delimited JSON, partitioned by tenant & date.
   305→    /// Glue crawlers project the schema automatically.
   306→    /// </summary>
   307→    public sealed class S3MetricPublisher : IMetricPublisher
   308→    {
   309→        private const string BucketName = "pulseops-warehouse-metrics";
   310→        private readonly IAmazonS3 _s3;
   311→        private readonly ILogger<S3MetricPublisher> _logger;
   312→
   313→        public S3MetricPublisher(IAmazonS3 s3, ILogger<S3MetricPublisher> logger)
   314→        {
   315→            _s3    = s3;
   316→            _logger = logger;
   317→        }
   318→
   319→        public async Task PublishAsync(MetricRecord record, CancellationToken token)
   320→        {
   321→            var key = BuildObjectKey(record);
   322→            var body = JsonSerializer.Serialize(record) + "\n"; // NDJSON
   323→
   324→            try
   325→            {
   326→                var response = await _s3.PutObjectAsync(new PutObjectRequest
   327→                {
   328→                    BucketName  = BucketName,
   329→                    Key         = key,
   330→                    ContentBody = body,
   331→                    ContentType = "application/x-ndjson",
   332→                    ServerSideEncryptionMethod = ServerSideEncryptionMethod.AES256
   333→                }, token);
   334→
   335→                if (response.HttpStatusCode != HttpStatusCode.OK)
   336→                {
   337→                    _logger.LogError("Failed to upload metric. S3 returned {StatusCode} for Key={Key}", response.HttpStatusCode, key);
   338→                    throw new Exception($"S3 upload failed with status {response.HttpStatusCode}");
   339→                }
   340→            }
   341→            catch (Exception ex)
   342→            {
   343→                _logger.LogError(ex, "Error publishing metric to S3.  Tenant={Tenant} MetricType={MetricType}", record.TenantId, record.MetricType);
   344→                throw;
   345→            }
   346→        }
   347→
   348→        private static string BuildObjectKey(MetricRecord record)
   349→        {
   350→            var date = record.PeriodEnd;
   351→            return $"{record.TenantId}/metric_type={record.MetricType}/year={date:yyyy}/month={date:MM}/day={date:dd}/{Guid.NewGuid()}.json";
   352→        }
   353→    }
   354→
   355→    #endregion
   356→}
