    86→        private readonly ILogger<TransformationStrategyRegistry> _logger;
    87→        private readonly ConcurrentDictionary<string, ITransformationStrategy> _cache = new(StringComparer.OrdinalIgnoreCase);
    88→
    89→        public TransformationStrategyRegistry(ILogger<TransformationStrategyRegistry> logger)
