    97→        /// </summary>
    98→        /// <exception cref="KeyNotFoundException">Thrown when no strategy exists.</exception>
    99→        public ITransformationStrategy GetOrThrow(string eventType)
   100→        {
   101→            if (eventType is null) throw new ArgumentNullException(nameof(eventType));
   102→
   103→            if (_cache.TryGetValue(eventType, out var strategy)) return strategy;
   104→
   105→            throw new KeyNotFoundException($"No transformation strategy registered for event type '{eventType}'.");
