   111→        public void Register(ITransformationStrategy strategy)
   112→        {
   113→            if (strategy is null) throw new ArgumentNullException(nameof(strategy));
   114→
   115→            if (!_cache.TryAdd(strategy.StrategyKey, strategy))
   116→            {
   117→                _logger.LogWarning("Strategy {Key} already registered – overriding instance.", strategy.StrategyKey);
   118→                _cache[strategy.StrategyKey] = strategy;
