   155→    /// <summary>
   156→    /// High-level orchestrator that fans-out raw events to the relevant strategy,
   157→    /// executes them in parallel with retry semantics, and fans-in KPI records.
   158→    /// </summary>
   159→    public sealed class TransformationEngine
   160→    {
   161→        private static readonly AsyncRetryPolicy RetryPolicy = Policy
   162→            .Handle<Exception>(ex => ex is not OperationCanceledException)
   163→            .WaitAndRetryAsync(
   164→                retryCount: 3,
   165→                sleepDurationProvider: attempt => TimeSpan.FromMilliseconds(100 * Math.Pow(2, attempt)), // 100ms, 200ms, 400ms
   166→                onRetry: (ex, ts, attempt, ctx) =>
   167→                {
   168→                    if (ctx.TryGetValue("Logger", out var obj) && obj is ILogger logger)
   169→                    {
   170→                        logger.LogWarning(ex,
   171→                            "Transient failure executing strategy (attempt {Attempt}/3). Retrying after {Delay}ms…",
   172→                            attempt, ts.TotalMilliseconds);
   173→                    }
   174→                });
   175→
   176→        private readonly TransformationStrategyRegistry _registry;
   177→        private readonly ILogger<TransformationEngine> _logger;
   178→
   179→        public TransformationEngine(
   180→            TransformationStrategyRegistry registry,
   181→            ILogger<TransformationEngine> logger)
   182→        {
   183→            _registry = registry ?? throw new ArgumentNullException(nameof(registry));
   184→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   185→        }
   186→
   187→        /// <summary>
   188→        /// Orchestrates transformation of a batch of raw events.
   189→        /// </summary>
   190→        public async Task<IReadOnlyCollection<KpiRecord>> ExecuteBatchAsync(
   191→            IReadOnlyCollection<RawEvent> events,
   192→            CancellationToken token = default)
   193→        {
   194→            if (events is null) throw new ArgumentNullException(nameof(events));
   195→
   196→            var kpiBag = new ConcurrentBag<KpiRecord>();
   197→            var stopwatch = Stopwatch.StartNew();
   198→
   199→            // Run transformations concurrently but keep within sane parallelism to protect lambda memory
   200→            await Parallel.ForEachAsync(events, new ParallelOptions
   201→            {
   202→                CancellationToken = token,
   203→                MaxDegreeOfParallelism = Environment.ProcessorCount // auto-scale based on memory
   204→            }, async (ev, ct) =>
   205→            {
   206→                // Strategy resolution (fast dictionary lookup)
   207→                ITransformationStrategy strategy;
   208→                try
   209→                {
   210→                    strategy = _registry.GetOrThrow(ev.EventType);
   211→                }
   212→                catch (Exception ex)
   213→                {
   214→                    _logger.LogError(ex, "Unable to find strategy for event type '{EventType}'. Dropping event.", ev.EventType);
   215→                    return; // swallow – DLQ routing handled upstream
   216→                }
   217→
   218→                // Execute with retry & jitter
   219→                var context = new Context().With("Logger", _logger);
   220→                var results = await RetryPolicy.ExecuteAsync(
   221→                    (_, _) => strategy.TransformAsync(ev, ct),
   222→                    context, ct);
   223→
   224→                foreach (var kpi in results)
   225→                {
   226→                    kpiBag.Add(kpi);
   227→                }
   228→            });
   229→
   230→            stopwatch.Stop();
   231→            _logger.LogInformation(
   232→                "Processed {EventCount} event(s) into {KpiCount} KPI record(s) in {ElapsedMs} ms.",
   233→                events.Count, kpiBag.Count, stopwatch.ElapsedMilliseconds);
   234→
   235→            return kpiBag.ToArray();
   236→        }
   237→    }
