   264→        {
   265→            // Basic validation
   266→            if (!raw.Payload.TryGetValue("start", out var startObj) ||
   267→                !raw.Payload.TryGetValue("end", out var endObj))
   268→            {
   269→                throw new InvalidOperationException("Invalid calendar event payload – missing start/end.");
   270→            }
   271→
   272→            var start = DateTimeOffset.Parse(startObj.ToString()!);
   273→            var end   = DateTimeOffset.Parse(endObj.ToString()!);
   274→            var durationMinutes = (end - start).TotalMinutes;
   275→
   276→            // Example heuristic: meetings with <= 2 attendees are considered 'focus'
   277→            var attendees = raw.Payload.TryGetValue("attendees", out var attendeeObj)
   278→                ? Convert.ToInt32(attendeeObj)
   279→                : 0;
   280→            var isFocusTime = attendees <= 2;
   281→
   282→            var value = isFocusTime ? durationMinutes : 0; // minutes of focus time
   283→            var kpi = new KpiRecord(
   284→                Name: KpiName,
   285→                Value: value,
   286→                Timestamp: raw.ReceivedAt,
   287→                Dimensions: new Dictionary<string, string>
   288→                {
   289→                    ["source"] = raw.SourceSystem,
   290→                    ["isRecurring"] = raw.Payload.TryGetValue("isRecurring", out var r) && (bool)r
   291→                        ? "true"
   292→                        : "false"
   293→                });
   294→
   295→            return Task.FromResult<IReadOnlyCollection<KpiRecord>>(new[] { kpi });
   296→        }
   297→    }
