    17→namespace PulseOps.Warehouse.KpiComputation
    18→{
    19→    #region Contracts & DTOs
    20→    /// <summary>
    21→    ///     Represents a unit of KPI result data emitted by a computation strategy.
    22→    /// </summary>
    23→    /// <param name="KpiName">Unique KPI identifier.</param>
    24→    /// <param name="Value">Computed numeric value.</param>
    25→    /// <param name="Timestamp">UTC timestamp at which computation occurred.</param>
    26→    /// <param name="Metadata">Additional metadata to enrich the result (labels, units, etc.).</param>
    27→    public sealed record KpiResult(
    28→        string KpiName,
    29→        double Value,
    30→        DateTime Timestamp,
    31→        IReadOnlyDictionary<string, string> Metadata);
    32→
    33→    /// <summary>
    34→    ///     Context object passed to KPI computation strategies.  Provides the raw data slice on which
    35→    ///     to operate as well as the analytic window in UTC.
    36→    /// </summary>
    37→    public sealed record KpiComputationContext(
    38→        IDictionary<string, object> Data,
    39→        DateTimeOffset WindowStart,
    40→        DateTimeOffset WindowEnd);
    41→
    42→    /// <summary>
    43→    ///     Implemented by all pluggable KPI computation strategies.
    44→    /// </summary>
    45→    public interface IKpiComputationStrategy
    46→    {
    47→        /// <summary>The canonical KPI identifier.</summary>
    48→        string KpiName { get; }
    49→
    50→        /// <summary>
    51→        ///     Performs the KPI computation asynchronously.
    52→        /// </summary>
    53→        /// <remarks>
    54→        ///     Implementations must be pure (side-effect free) and thread-safe.  They should
    55→        ///     never mutate the incoming context.
    56→        /// </remarks>
    57→        ValueTask<KpiResult> ComputeAsync(
    58→            KpiComputationContext context,
    59→            CancellationToken cancellationToken = default);
    60→    }
    61→    #endregion
    62→
    63→    #region Attribute-based discovery
    64→    /// <summary>
    65→    ///     Decorating a class with <see cref="KpiStrategyAttribute"/> auto-registers it with
    66→    ///     <see cref="KpiStrategyRegistry"/> at startup time.
    67→    /// </summary>
    68→    [AttributeUsage(AttributeTargets.Class, Inherited = false)]
    69→    public sealed class KpiStrategyAttribute : Attribute
    70→    {
    71→        public KpiStrategyAttribute(string kpiName) => KpiName = kpiName;
    72→
    73→        public string KpiName { get; }
    74→    }
    75→    #endregion
    76→
    77→    #region Strategy Registry
    78→    /// <summary>
    79→    ///     Thread-safe runtime registry that maps KPI keys to active computation strategies.
    80→    ///     Discoverable via DI singleton.
    81→    /// </summary>
    82→    public sealed class KpiStrategyRegistry
    83→    {
    84→        private readonly ILogger<KpiStrategyRegistry> _logger;
    85→        private readonly ConcurrentDictionary<string, IKpiComputationStrategy> _strategies;
    86→
    87→        public KpiStrategyRegistry(ILogger<KpiStrategyRegistry> logger)
    88→        {
    89→            _logger = logger;
    90→            _strategies = new ConcurrentDictionary<string, IKpiComputationStrategy>(
    91→                StringComparer.OrdinalIgnoreCase);
    92→
    93→            DiscoverStrategies();
    94→        }
    95→
    96→        /// <summary>
    97→        ///     Returns <c>true</c> if a strategy for <paramref name="kpiName"/> is present.
    98→        /// </summary>
    99→        public bool Contains(string kpiName) => _strategies.ContainsKey(kpiName);
   100→
   101→        /// <summary>
   102→        ///     Retrieves the strategy or throws an informative <see cref="KeyNotFoundException"/>.
   103→        /// </summary>
   104→        /// <exception cref="KeyNotFoundException">Thrown when no strategy is registered.</exception>
   105→        public IKpiComputationStrategy Get(string kpiName)
   106→        {
   107→            if (!_strategies.TryGetValue(kpiName, out var strategy))
   108→            {
   109→                throw new KeyNotFoundException(
   110→                    $"No KPI computation strategy registered for key '{kpiName}'. " +
   111→                    $"Ensure a class is decorated with [KpiStrategy(\"{kpiName}\")].");
   112→            }
   113→
   114→            return strategy;
   115→        }
   116→
   117→        /// <summary>
   118→        ///     Adds or replaces a strategy at runtime.  Used by feature-flag rollouts.
   119→        /// </summary>
   120→        public void Upsert(IKpiComputationStrategy strategy)
   121→        {
   122→            _strategies.AddOrUpdate(strategy.KpiName, strategy, (_, __) => strategy);
   123→            _logger.LogInformation("Registered KPI strategy: {KpiName} ({Type})",
   124→                strategy.KpiName, strategy.GetType().FullName);
   125→        }
   126→
   127→        private void DiscoverStrategies()
   128→        {
   129→            var stopwatch = System.Diagnostics.Stopwatch.StartNew();
   130→
   131→            // Scan all loaded assemblies (excluding Microsoft / System to speed things up).
   132→            var assemblies = AppDomain.CurrentDomain
   133→                                      .GetAssemblies()
   134→                                      .Where(a => !a.FullName.StartsWith("System.", StringComparison.Ordinal) &&
   135→                                                  !a.FullName.StartsWith("Microsoft.", StringComparison.Ordinal))
   136→                                      .ToArray();
   137→
   138→            int count = 0;
   139→            foreach (var assembly in assemblies)
   140→            {
   141→                foreach (var candidate in assembly.GetTypes())
   142→                {
   143→                    if (candidate.IsAbstract ||
   144→                        candidate.IsInterface ||
   145→                        !typeof(IKpiComputationStrategy).IsAssignableFrom(candidate))
   146→                        continue;
   147→
   148→                    var attribute = candidate.GetCustomAttribute<KpiStrategyAttribute>();
   149→                    if (attribute is null)
   150→                        continue;
   151→
   152→                    // Instantiate via Activator; strategy must have a public parameterless ctor.
   153→                    if (Activator.CreateInstance(candidate) is not IKpiComputationStrategy instance)
   154→                    {
   155→                        _logger.LogWarning("Failed to instantiate KPI strategy '{StrategyType}'. Skipping.",
   156→                            candidate.FullName);
   157→                        continue;
   158→                    }
   159→
   160→                    Upsert(instance);
   161→                    count++;
   162→                }
   163→            }
   164→
   165→            stopwatch.Stop();
   166→            _logger.LogInformation("KPI strategy discovery complete — {Count} strategies loaded in {ElapsedMs}ms.",
   167→                count, stopwatch.ElapsedMilliseconds);
   168→        }
   169→    }
   170→    #endregion
   171→
   172→    #region Orchestrator
   173→    /// <summary>
   174→    ///     Orchestrates KPI computations in parallel, respecting cancellation tokens and
   175→    ///     aggregating failures in a structured way.
   176→    /// </summary>
   177→    public sealed class KpiComputationOrchestrator
   178→    {
   179→        private readonly KpiStrategyRegistry _registry;
   180→        private readonly ILogger<KpiComputationOrchestrator> _logger;
   181→
   182→        public KpiComputationOrchestrator(
   183→            KpiStrategyRegistry registry,
   184→            ILogger<KpiComputationOrchestrator> logger)
   185→        {
   186→            _registry = registry;
   187→            _logger = logger;
   188→        }
   189→
   190→        /// <summary>
   191→        ///     Computes a batch of KPI names against the same data context, executing work in
   192→        ///     parallel while enforcing a configurable degree of parallelism.
   193→        /// </summary>
   194→        /// <param name="kpiNames">The KPI identifiers to compute.</param>
   195→        /// <param name="context">Shared context passed to each strategy.</param>
   196→        /// <param name="maxParallelism">Limits in-flight computations (1-32 recommended).</param>
   197→        /// <param name="cancellationToken">Token to cancel the entire batch.</param>
   198→        /// <returns>Collection of <see cref="KpiResult"/> plus any failures (exceptions).</returns>
   199→        public async Task<(IReadOnlyList<KpiResult> Results, IReadOnlyList<Exception> Errors)> ComputeBatchAsync(
   200→            IEnumerable<string> kpiNames,
   201→            KpiComputationContext context,
   202→            int maxParallelism = 8,
   203→            CancellationToken cancellationToken = default)
   204→        {
   205→            if (context is null) throw new ArgumentNullException(nameof(context));
   206→            if (kpiNames is null) throw new ArgumentNullException(nameof(kpiNames));
   207→            if (maxParallelism is < 1 or > 32)
   208→                throw new ArgumentOutOfRangeException(nameof(maxParallelism),
   209→                    "maxParallelism must be between 1 and 32.");
   210→
   211→            var resultBag = new ConcurrentBag<KpiResult>();
   212→            var errorBag = new ConcurrentBag<Exception>();
   213→
   214→            using var semaphore = new SemaphoreSlim(maxParallelism);
   215→
   216→            var tasks = kpiNames.Select(async kpiName =>
   217→            {
   218→                await semaphore.WaitAsync(cancellationToken).ConfigureAwait(false);
   219→                try
   220→                {
   221→                    var strategy = _registry.Get(kpiName);
   222→                    var result = await strategy.ComputeAsync(context, cancellationToken).ConfigureAwait(false);
   223→                    resultBag.Add(result);
   224→                }
   225→                catch (OperationCanceledException)
   226→                {
   227→                    // Bubble up cancellation — don’t treat as error.
   228→                    throw;
   229→                }
   230→                catch (Exception ex)
   231→                {
   232→                    errorBag.Add(ex);
   233→                    _logger.LogError(ex, "Failed to compute KPI '{Kpi}'.", kpiName);
   234→                }
   235→                finally
   236→                {
   237→                    semaphore.Release();
   238→                }
   239→            });
   240→
   241→            try
   242→            {
   243→                await Task.WhenAll(tasks).ConfigureAwait(false);
   244→            }
   245→            catch (OperationCanceledException)
   246→            {
   247→                // caller cancelled — swallow here, propagate via token.
   248→            }
   249→
   250→            return (resultBag.ToArray(), errorBag.ToArray());
   251→        }
   252→    }
   253→    #endregion
