   255→    #region Sample Strategies
   256→    // NOTE: These sample implementations are intentionally simple.  Production strategies would,
   257→    //       for example, query Athena / S3 parquet, leverage Apache Arrow, or perform complex ML
   258→    //       inference via SageMaker endpoints.  The samples demonstrate the pluggability only.
   259→
   260→    /// <summary>
   261→    ///     Focus-time ratio = (Coding/Deep work minutes) ÷ Total minutes in analytic window.
   262→    ///     Requires that the context includes:
   263→    ///         - "DeepWorkMinutes" (double)
   264→    ///         - "WindowMinutes"   (double)
   265→    /// </summary>
   266→    [KpiStrategy("focus_time_ratio")]
   267→    public sealed class FocusTimeRatioStrategy : IKpiComputationStrategy
   268→    {
   269→        public string KpiName => "focus_time_ratio";
   270→
   271→        public ValueTask<KpiResult> ComputeAsync(
   272→            KpiComputationContext context,
   273→            CancellationToken cancellationToken = default)
   274→        {
   275→            if (!context.Data.TryGetValue("DeepWorkMinutes", out var deepWork) ||
   276→                !context.Data.TryGetValue("WindowMinutes", out var window))
   277→                throw new ArgumentException("Required keys missing: DeepWorkMinutes or WindowMinutes");
   278→
   279→            double deepWorkMinutes = Convert.ToDouble(deepWork);
   280→            double windowMinutes = Convert.ToDouble(window);
   281→
   282→            if (windowMinutes <= 0)
   283→                throw new DivideByZeroException("WindowMinutes must be > 0");
   284→
   285→            var ratio = deepWorkMinutes / windowMinutes;
   286→
   287→            var metadata = new Dictionary<string, string>
   288→            {
   289→                ["unit"] = "ratio",
   290→                ["deepWorkMinutes"] = deepWorkMinutes.ToString("F0"),
   291→                ["windowMinutes"] = windowMinutes.ToString("F0")
   292→            };
   293→
   294→            var result = new KpiResult(
   295→                KpiName,
   296→                Math.Round(ratio, 4),
   297→                DateTime.UtcNow,
   298→                metadata);
   299→
   300→            return ValueTask.FromResult(result);
