// Purpose: Orchestrator optimized for small batch sizes with pre-warmed dependencies
public sealed class MicroBatchOrchestrator
{
    // Singleton registry - no per-invocation discovery
    private static readonly Lazy<TransformationStrategyRegistry> _registry =
        new(() => new TransformationStrategyRegistry(), LazyThreadSafetyMode.ExecutionAndPublication);

    // Pre-warmed S3 client
    private static readonly IAmazonS3 _s3Client = new AmazonS3Client();

    private readonly BatchedS3Writer _writer;

    public MicroBatchOrchestrator()
    {
        _writer = new BatchedS3Writer(_s3Client);
    }

    public async Task ProcessMicroBatchAsync(IEnumerable<SQSMessage> messages, CancellationToken ct)
    {
        var results = new List<KpiRecord>();

        // Parallel processing with bounded concurrency
        await Parallel.ForEachAsync(messages, new ParallelOptions
        {
            MaxDegreeOfParallelism = 4,  // Reduced for small batches
            CancellationToken = ct
        }, async (msg, token) =>
        {
            var strategy = _registry.Value.GetOrThrow(msg.EventType);
            var result = await strategy.TransformAsync(msg.ToRawEvent(), token);
            lock (results) results.AddRange(result);
        });

        // Single coalesced S3 write
        await _writer.WriteBatchAsync(results, ct);
    }
}
```

