// Purpose: Coalesce multiple small writes into single S3 operation
public sealed class BatchedS3Writer
{
    private readonly IAmazonS3 _s3;

    public async Task WriteBatchAsync(IReadOnlyCollection<KpiRecord> records, CancellationToken ct)
    {
        if (records.Count == 0) return;

        // Single NDJSON file for entire micro-batch
        var ndjson = string.Join('\n', records.Select(r => JsonSerializer.Serialize(r)));
        var key = $"micro-batch/{DateTime.UtcNow:yyyy/MM/dd/HH}/{Guid.NewGuid()}.jsonl";

        await _s3.PutObjectAsync(new PutObjectRequest
        {
            BucketName = "pulseops-data-lake",
            Key = key,
            ContentBody = ndjson
        }, ct);
    }
}
